const d = new Date();
msg.payload = d.toLocaleString('ko-KR', { hour12: false });
return msg;

const s = (msg.payload || '').toString();
const parts = s.split('|').map(x => x.trim());
const w = parts.find(x => x.startsWith('W:'));
let ssid = '-';
let ip = '-';
if (w) {
  const rest = w.slice(2).trim();
  const k = rest.lastIndexOf(' ip=');
  if (k >= 0 && rest.startsWith('ssid=')) {
    ssid = rest.slice(5, k).trim();
    ip = rest.slice(k + 4).trim();
    if (!ssid) ssid = '-';
    if (!ip) ip = '-';
    if (ip === '0.0.0.0') ip = '-';
  }
}
return [[{ payload: ssid }], [{ payload: ip }]];

const s=(msg.payload||'').toString().trim();
msg._ok = (s==='active');
msg.payload = msg._ok ? 'online' : 'offline';
return msg;

const s=(msg.payload||'').toString().trim();
msg._ok = (s==='active');
msg.payload = msg._ok ? 'online' : 'offline';
return msg;

const now=Date.now();
const ls=flow.get('arduinoLastStatusMs')||0;
const lt=flow.get('arduinoLastTeleMs')||0;
const ok=((now-ls)<30000)||((now-lt)<5000);
msg._ok=ok;
msg.payload=ok?'정상':'미수신';
msg.statusAge=ls?Math.floor((now-ls)/1000):null;
msg.teleAge=lt?Math.floor((now-lt)/1000):null;
const raw=(flow.get('lastTeleStr')||'').toString();
msg.telePreview = raw.length>200 ? raw.slice(0,200)+'…' : raw;
return msg;

// tele 예)
// S:led_a1=0 ... pump_b2=1 | A:led_a1=0 ... | T:pump_a1=30/90 ...
//
// 중요: tele이 1초마다 오기 때문에, UI 드롭다운(dd_*)을 매번 덮어쓰면 "시간이 계속 바뀌는" 것처럼 보일 수 있습니다.
// 여기서는 on_/off_ 초 값만 반영하고(dd_ 분/초 UI 갱신은 하지 않음), 드롭다운은 사용자가 바꾼 값이 유지되도록 합니다.

const s=(msg.payload||'').toString();
function parseKV(part){
  const out={};
  (part||'').trim().split(/\s+/).forEach(tok=>{
    const m=tok.match(/^([^=]+)=(.+)$/);
    if(!m) return;
    out[m[1]] = m[2];
  });
  return out;
}

const ps = s.split('|').map(x=>x.trim());
const pS = ps.find(x=>x.startsWith('S:'));
const pA = ps.find(x=>x.startsWith('A:'));
const pT = ps.find(x=>x.startsWith('T:'));

const kvS = parseKV(pS ? pS.slice(2) : '');
const kvA = parseKV(pA ? pA.slice(2) : '');
const kvT = parseKV(pT ? pT.slice(2) : '');

const chKeys = ['led_a1','led_a2','pump_a1','pump_a2','led_b1','pump_b1','pump_b2'];

const out=[];
chKeys.forEach(k=>{
  if(k in kvS) {
    const v = (kvS[k]==='1')?1:0;
    flow.set(k, v);
    out.push({topic:k, payload: v});
  }
});
chKeys.forEach(k=>{
  const ak = 'auto_'+k;
  if(k in kvA) {
    const v = (kvA[k]==='1')?1:0;
    flow.set(ak, v);
    out.push({topic:ak, payload: v});
  }
});

Object.keys(kvT).forEach(k=>{
  // pump_x=30/90
  const m = (kvT[k]||'').match(/^(\d+)\/(\d+)$/);
  if(!m) return;
  const onV = parseInt(m[1],10);
  const offV = parseInt(m[2],10);
  const onK = 'on_'+k;
  const offK = 'off_'+k;
  flow.set(onK, onV);
  flow.set(offK, offV);
  out.push({topic:onK, payload: onV});
  out.push({topic:offK, payload: offV});
});

return [out];

const devId = flow.get('deviceId') || 'cronusfarm-01';
flow.set('deviceId', devId);

const k = (msg.topic||'').toString().trim();
if(!k) return null;
const v = (msg.payload===1 || msg.payload===true || msg.payload==='1' || msg.payload==='on') ? 1 : 0;

// 스위치 조작 시: 해당 채널을 수동(auto=0)으로 고정하고, 즉시 ON/OFF 값을 cmd로 발행
// - 반드시 2회 발행(auto -> state). Function 노드 출력 1개에서 여러 메시지를 내보내려면
//   [[msg1, msg2]] 형태(출력 포트별 메시지 배열)로 반환해야 합니다.
const t = `cronusfarm/${devId}/cmd`;
const m1 = {topic:t, payload:`auto_${k}=0`};
const m2 = {topic:t, payload:`${k}=${v}`};
return [[m1, m2]];

const key = (msg.topic || '').toString();
const v = Number(msg.payload);
if (!key) return null;
flow.set(key, isNaN(v) ? 0 : v);
const mm = key.match(/^dd_(on|off)_(pump_[a-z0-9]+)_(m|s)$/);
if (!mm) return null;
const kind = mm[1];
const pk = mm[2];
const minutes = Number(flow.get('dd_' + kind + '_' + pk + '_m')) || 0;
const seconds = Number(flow.get('dd_' + kind + '_' + pk + '_s')) || 0;
let t = minutes * 60 + seconds;
if (t < 1) t = 1;
if (t > 3600) t = 3600;
const outTopic = kind + '_' + pk;
flow.set(outTopic, t);
msg.topic = outTopic;
msg.payload = t;
return msg;

const devId = flow.get('deviceId') || 'cronusfarm-01';
flow.set('deviceId', devId);

const key = (msg.topic||'').toString();
const val = msg.payload;
if (key) flow.set(key, val);

const keys = [
  'led_a1','led_a2','pump_a1','pump_a2','led_b1','pump_b1','pump_b2',
  'auto_led_a1','auto_led_a2','auto_pump_a1','auto_pump_a2','auto_led_b1','auto_pump_b1','auto_pump_b2',
  'on_pump_a1','off_pump_a1','on_pump_a2','off_pump_a2','on_pump_b1','off_pump_b1','on_pump_b2','off_pump_b2'
];

const parts=[];
keys.forEach(k=>{
  const v = flow.get(k);
  if (v === undefined || v === null) return;
  parts.push(`${k}=${v}`);
});

msg.topic = `cronusfarm/${devId}/cmd`;
msg.payload = parts.join(' ');
return msg;
